"use strict";exports.id=9331,exports.ids=[9331],exports.modules={2728:(a,b,c)=>{c.d(b,{Eb:()=>f,JN:()=>i,Jz:()=>h,KA:()=>g,Pl:()=>d,VS:()=>e});let d=[{title:"Certified Penetration Tester",description:"Learn to identify vulnerabilities, perform penetration testing, and simulate real-world cyber attacks with hands-on ethical hacking training built for modern security professionals.",tags:["Ethical Hackers","Security Analysts"],link:"/trainings/certified-penetration-tester"},{title:"Certified Security Operations Center (SOC) Analyst",description:"Master SIEM, incident response, and threat hunting in modern SOC environments.",tags:["SOC Analysts","Incident Responders"],link:"/trainings/certified-soc-analyst"},{title:"Certified Red Team Professional",description:"Advanced penetration testing, red teaming, and vulnerability assessment techniques.",tags:["Red Team Operators","Advanced Penetration Testers"],link:"/trainings/certified-red-team-professional"},{title:"Certified Cyber Threat Intelligence Analyst",description:"Learn threat intelligence fundamentals and build defense strategies using MISP and global cyber threat intelligence feeds.",tags:["Threat Analysts","SOC Teams"],link:"/trainings/certified-cyber-threat-intelligence-analyst"},{title:"Certified Cloud Security Professional",description:"Learn secure cloud practices and build safer applications across modern cloud environments.",tags:["Cloud Engineers","Security Architects"],link:"/trainings/certified-cloud-security-professional"},{title:"Certified Security Aware User",description:"Learn essential cybersecurity practices to recognize threats and protect personal and organizational information.",tags:["Employees","Staff members","End users"],link:"/trainings/certified-security-aware-user"}],e={hero:{titlePart1:"NIST National Initiative for",titlePart2:"Cybersecurity Education",titlePart3:"",description:"Cybertronium certifications focus on key cyber job roles and best practices, and are aligned to the NICE Workforce Framework."},textSection:{subheading:"Workforce Alignment",headingLine1:"Why Cybertronium Certifications are",headingLine2:"mapped to NICE framework?",paragraphs:["For SOC managers and CISOs : Preventing a critical attack is one of the primary responsibilities of any SOC. It is imperative that your team possesses the required skills to prevent this attack. Given that most SOC Managers or CISOs believe their team to be under-skilled and under-qualified to prevent a critical attack, having a framework in place provides a roadmap to skill-training and qualification. By using the NICE Cybersecurity Framework, SOC managers can detail exactly which role the members of the team are taking, which skills are required for the assigned role, and what training needs to take place for them to be successful.","For Recruiters and HR Managers: It is becoming increasingly difficult and competitive to hire qualified candidates to work on the cybersecurity team. Aligning with NICE KSAs allows HR managers to compare candidates more easily from diverse backgrounds. This will allow an additional tool in the arsenal with the ability to run prospective candidates through exercises that will test if they have the required skills to fill the specified role. Using NICE Work Roles and Skills will also help recruiters to determine accurate and applicable training programs, leading to better qualified employees and higher employee retention."]},overviewSection:{subheading:"Framework Overview",heading:"About NIST NICE Framework",description:"",sideContent:{paragraphs:["National Initiative for Cybersecurity Education (NICE) is a partnership between government, academia, and the private sector to address cybersecurity education, like Malaysia's very own Global ACE Framework. NICE is led by the National Institute of Standards and Technology (NIST). In May 2019, the President of the United States signed an Executive Order to grow America's cybersecurity workforce and strengthen the nation's cybersecurity. This encourages widespread adoption of this framework globally including Singapore.","The NICE Framework is a common taxonomy and lexicon that categorizes and describes cybersecurity work and workers regardless of organization or industry. This national resource aims to standardize cybersecurity workforce definitions across the public, private, and academic sectors so that the entire cybersecurity industry speaks a common language and shares common goals."],linkText:"NICE Framework can be accessed at: ",linkUrl:"https://niccs.cisa.gov/workforce-development/cyber-security-workforce-framework"},listItems:[],bottomImageAlt:"NICE Workforce Framework Categories",bottomImageSrc:""},certificationsSection:{headingLine1:"Cybertronium",headingLine2:"NICE Framework",headingLine3:"Mapped Certifications",description:"Cybertronium offers a wide range of ISO/IEC 17024 accredited cybersecurity certifications designed to build practical skills across offensive security, defense operations, cloud security, threat intelligence, secure development, and security awareness for professionals at different experience levels."}},f=[{title:"Certified Penetration Tester",description:"Learn to identify vulnerabilities, perform penetration testing, and simulate real-world cyber attacks with hands-on ethical hacking training built for modern security professionals.",tags:["Ethical Hackers","Security Analysts"],link:"/trainings/certified-penetration-tester"},{title:"Certified Security Operations Center (SOC) Analyst",description:"Master SIEM, incident response, and threat hunting in modern SOC environments.",tags:["SOC Analysts","Incident Responders"],link:"/trainings/certified-soc-analyst"},{title:"Certified Red Team Professional",description:"Advanced penetration testing, red teaming, and vulnerability assessment techniques.",tags:["Red Team Operators","Advanced Penetration Testers"],link:"/trainings/certified-red-team-professional"},{title:"Certified Cyber Threat Intelligence Analyst",description:"Learn threat intelligence fundamentals and build defense strategies using MISP and global cyber threat intelligence feeds.",tags:["Threat Analysts","SOC Teams"],link:"/trainings/certified-cyber-threat-intelligence-analyst"}],g={hero:{titlePart1:"Global ACE",titlePart2:"Framework",titlePart3:"",description:"Cybertronium certifications align with the Global ACE Framework, recognized across OIC and ASEAN countries."},textSection:{subheading:"Global Recognition",headingLine1:"Global ACE Certification",headingLine2:"",paragraphs:["Cybertronium certifications are aligned to Global ACE Framework Scheme from Cybersecurity Malaysia, an agency under Ministry of Communications and Multimedia, Government of Malaysia.","Global ACE is a National framework scheme accepted by Organization of Islamic Cooperation (OIC) member countries and the ASEAN countries."]},overviewSection:{subheading:"Framework Overview",heading:"About Global ACE Framework",description:"",sideContent:{paragraphs:["The Global ACE Certification is a holistic framework of cybersecurity professional certification that outlines the overall approach, independent assessments, impartiality of examinations, competencies of trainers, identification and classification of cyber security domains and the requirements of professional memberships. The scheme is a large-scale systematic plan of actions to certify and recognise the cybersecurity workforce. It is industry-driven and vendor-neutral, developed in collaboration with government agencies, industry partners and academia.",'The heart of the Global ACE Certification is the framework that provides a standard base and means of acknowledging the "knowledge, skills and attitudes" for the workforce in the cyber security sector. The framework will be the base for impartial examinations and guideline for certifications.']},listItems:[],bottomDescription:""},certificationsSection:{headingLine1:"Cybertronium",headingLine2:"Global ACE",headingLine3:"Framework Mapped Certifications",description:"Cybertronium offers a wide range of ISO/IEC 17024 accredited cybersecurity certifications designed to build practical skills across offensive security, defense operations, cloud security, threat intelligence, secure development, and security awareness for professionals at different experience levels."}},h=[{title:"Certified Penetration Tester",description:"Learn to identify vulnerabilities, perform penetration testing, and simulate real-world cyber attacks with hands-on ethical hacking training built for modern security professionals.",tags:["Ethical Hackers","Security Analysts"],link:"/trainings/certified-penetration-tester"},{title:"Certified Security Operations Center (SOC) Analyst",description:"Master SIEM, incident response, and threat hunting in modern SOC environments.",tags:["SOC Analysts","Incident Responders"],link:"/trainings/certified-soc-analyst"},{title:"Certified Red Team Professional",description:"Advanced penetration testing, red teaming, and vulnerability assessment techniques.",tags:["Red Team Operators","Advanced Penetration Testers"],link:"/trainings/certified-red-team-professional"},{title:"Certified Cyber Threat Intelligence Analyst",description:"Learn threat intelligence fundamentals and build defense strategies using MISP and global cyber threat intelligence feeds.",tags:["Threat Analysts","SOC Teams"],link:"/trainings/certified-cyber-threat-intelligence-analyst"}],i={hero:{titlePart1:"MITRE",titlePart2:"Adversarial Tactics, Techniques, &",titlePart3:"Common Knowledge",description:"Cybertronium certifications aligned with MITRE ATT&CK help professionals understand attacker behavior, strengthen detection strategies, and build effective incident response playbooks."},textSection:{subheading:"Threat Intelligence",headingLine1:"ATT&CK Framework Integration",headingLine2:"",paragraphs:["The ATT&CK framework includes resources that are purpose-built to help develop analytics that detect the techniques used by attackers as they attempt to breach, explore, and exfiltrate data from your databases. ATT&CK framework also provides information on hacking collectives or groups and the campaigns they've conducted, allowing you to be as prepared as possible for a future attack. All these resources are mapped in Cybertronium certifications to provide real-world details on attacks and learn how to defend them at real-time.",'Cybertronium certifications mapped with ATT&CK framework helps you to understand how attackers operate so that you can plan and build response playbooks to mitigate attacker incidents. Armed with this knowledge and "attack playbooks" you are now better prepared to understand how your adversaries prepare for, launches, execute their attacks to achieve specific desired objectives, so you can defend and eliminate attacks.']},overviewSection:{subheading:"Framework Overview",heading:"About MITRE ATT&CK Framework",description:'MITRE\'s ATT&CK Framework is defined as globally accessible knowledge base of adversary tactics and techniques based on real-world observations. The ATT&CK knowledge base is used as a foundation for the development of specific threat models and methodologies in the private sector, in government, and in the cybersecurity product and service community. This framework describes how attackers penetrate networks and then move laterally, escalate privileges, create a persistent state, or generally evade your defenses. ATT&CK looks at the "problem" from the perspective of the attacker, helping cybersecurity professionals determine what goals the attacker is aiming to achieve and what methods the attacker will use to achieve their goals. The framework organizes attacker behaviors into a series of tactics, specific technical objectives that an attacker wants to achieve. For example, an attacker may perform lateral movement to move to a different part of the network where the specific data they are looking for is waiting to be exfiltrated.',sideContent:{paragraphs:["Within each tactic category ATT&CK defines a series of techniques. Each technique describes one way an attacker may attempt to achieve their objective. Each tactic contains multiple techniques because different attackers may deploy different attack methodologies based on their own knowledge or circumstance (availability of tools, system configuration, etc.). Each technique defined in ATT&CK includes a description of the method deployed by the attacker, the systems, or platforms the methodologies apply to, and, where known, which attackers or attack groups have been associated with the defined technique. Techniques also provide the process by which the SOC team can mitigate attacker behavior along with any published references to the technique being deployed."]},listItems:[],bottomDescription:""},certificationsSection:{headingLine1:"Cybertronium",headingLine2:"MITRE ATT&CK Framework",headingLine3:"Mapped Certifications",description:"Cybertronium offers a wide range of ISO/IEC 17024 accredited cybersecurity certifications designed to build practical skills across offensive security, defense operations, cloud security, threat intelligence, secure development, and security awareness for professionals at different experience levels."}}},6592:(a,b,c)=>{a.exports=c.p+"static/media/hrd-corp.0f077c4edb84150b.webp"},8455:(a,b,c)=>{c.d(b,{K:()=>g});let d={"/":{title:"Cybertronium | Cybersecurity Services, SOC & Training",description:"Cybertronium delivers penetration testing, cloud security, 24x7 SOC/MDR and ISO 17024 certified cybersecurity training for businesses across Asia."},"/about-us":{title:"Cybertronium | Cybersecurity Services & Training in Asia",description:"Cybertronium is a leading cybersecurity firm in Asia, delivering managed security services, CTEM, AI security, SOC operations, training, and cyber resilience solutions."},"/services":{title:"Cybersecurity Services | Penetration Testing, MDR & AI Security",description:"Explore Cybertronium's cybersecurity services, including vulnerability assessments, penetration testing, MDR/SOC, cloud security, consulting, AI security, and cyber resilience solutions for modern enterprises."},"/ctem":{title:"CTEM as a Service | Continuous Threat Exposure Management",description:"Reduce cyber risk with Cybertronium's CTEM as a Service. Continuously discover, prioritize, validate, and remediate exposures through attack surface management, threat intelligence, and risk-based security."},"/services/zero-trust-implementation":{title:"Zero Trust Implementation Services | Cybertronium",description:"Implement a Zero Trust security architecture with Cybertronium's expert consultants and reduce unauthorized access, lateral movement and breach risk."},"/services/vulnerability-assessment":{title:"Vulnerability Assessment Services | Cybertronium",description:"Identify and remediate security weaknesses before attackers do. Cybertronium's vulnerability assessments uncover risks across networks, apps and cloud."},"/services/penetration-testing":{title:"Penetration Testing Services | Cybertronium",description:"Cybertronium's certified penetration testers simulate real-world cyberattacks to expose exploitable vulnerabilities and strengthen your security posture."},"/services/app-security-services":{title:"Application Security Testing Services | Cybertronium",description:"Secure your web, mobile and API applications with Cybertronium's application security testing, catching code-level flaws before they become breaches."},"/services/red-purple-teaming":{title:"Red & Purple Teaming Services | Cybertronium",description:"Test your defenses against real adversary tactics with Cybertronium's Red and Purple Team engagements, improving detection and incident response."},"/services/firmware-security":{title:"Firmware Security Assessment | Cybertronium",description:"Cybertronium assesses firmware and embedded device security to uncover hidden vulnerabilities that standard security testing often misses."},"/services/compromise-assessment":{title:"Compromise Assessment Services | Cybertronium",description:"Find out if you've already been breached. Cybertronium's compromise assessment uncovers active threats, indicators of compromise and hidden attackers."},"/services/cybersecurity-maturity-assessment":{title:"Cybersecurity Maturity Assessment | Cybertronium",description:"Benchmark your security maturity against industry frameworks with Cybertronium and build a clear, prioritized roadmap to strengthen your defenses."},"/services/strategy-consulting":{title:"Cybersecurity Strategy & Consulting | Cybertronium",description:"Align cybersecurity with business goals. Cybertronium's consultants help you build a practical, risk-based security strategy and roadmap."},"/services/governance-risk-compliance":{title:"Governance, Risk & Compliance (GRC) | Cybertronium",description:"Cybertronium helps organizations build robust GRC programs that meet regulatory requirements and reduce enterprise-wide cyber risk."},"/services/secure-digital-transformation":{title:"Secure Digital Transformation Services | Cybertronium",description:"Adopt new technology with confidence. Cybertronium embeds security into every stage of your digital transformation journey, from strategy to rollout."},"/services/digital-forensics-incident-response":{title:"Digital Forensics & Incident Response | Cybertronium",description:"When a breach happens, every minute counts. Cybertronium's DFIR experts investigate, contain and remediate incidents to minimize business impact."},"/services/mobile-threat-defense":{title:"Mobile Threat Defense (MTD) Services | Cybertronium",description:"Protect corporate mobile devices from malware, phishing and network attacks with Cybertronium's Mobile Threat Defense solutions and consulting."},"/services/ciso-as-a-service":{title:"Virtual CISO (vCISO) Services | Cybertronium",description:"Get strategic security leadership without the full-time cost. Cybertronium's vCISO service offers expert guidance to manage and reduce cyber risk."},"/services/cloud-detection-response":{title:"Cloud Detection and Response (CDR) | Cybertronium",description:"Cybertronium's 24x7 Cloud Detection and Response service monitors AWS, Azure and other cloud platforms to detect, contain and respond to threats fast."},"/services/cloud-security-posture-management":{title:"Cloud Security Posture Management | Cybertronium",description:"Continuously monitor and harden your cloud configuration with Cybertronium's CSPM service, reducing misconfigurations and cloud security risk."},"/services/cloud-security-consulting":{title:"Cloud Security Consulting Services | Cybertronium",description:"Cybertronium's cloud security consultants help design, secure and govern your IaaS and SaaS environments across Azure, AWS and other cloud platforms."},"/services/managed-security-awareness":{title:"Managed Security Awareness Program | Cybertronium",description:"Turn employees into your strongest defense. Cybertronium's managed security awareness program builds lasting, organization-wide cyber-safe habits."},"/services/soc-for-sme":{title:"SOC for SME | Affordable Managed SOC & Cybersecurity Services",description:"Protect your business with Cybertronium's SOC for SME solution. Get 24/7 threat monitoring, MDR, SIEM, incident response, compliance support, and enterprise-grade cybersecurity at an affordable cost."},"/services/soc-as-a-service":{title:"SOC as a Service | AI-Driven 24x7 Security Operations",description:"Cybertronium's managed SOC delivers 24/7 threat detection, SIEM, SOAR, UEBA, AI-driven security operations, threat hunting, and incident response to strengthen cyber resilience."},"/services/ai-security":{title:"AI Security Services | LLM Security, AI Governance & ISO 42001",description:"Secure your AI ecosystem with Cybertronium's AI Security Services. From LLM penetration testing and AI red teaming to AI governance and ISO 42001 compliance, we help organizations manage AI risk and resilience."},"/trainings":{title:"Cybersecurity Trainings & Certifications | Cybertronium",description:"Explore ISO 17024 audited, NICE Framework mapped cybersecurity trainings and certifications, delivered hands-on by Cybertronium's seasoned consultants."},"/trainings/iso-17024":{title:"ISO 17024 Certification Body | Cybertronium",description:"Cybertronium is an ISO/IEC 17024 accredited certification body, delivering globally recognized cybersecurity certifications across multiple domains."},"/trainings/globalace":{title:"GlobalACE Accredited Trainings | Cybertronium",description:"Cybertronium's cybersecurity courses are accredited under GlobalACE, the vendor-neutral framework developed by Cybersecurity Malaysia and industry partners."},"/trainings/nist-nice":{title:"NICE Framework Mapped Trainings | Cybertronium",description:"Cybertronium's cybersecurity trainings are mapped to the NIST NICE Framework, ensuring courses build the exact skills today's cyber workforce needs."},"/trainings/globalace-framework":{title:"GlobalACE Framework Mapped Trainings | Cybertronium",description:"Cybertronium courses are mapped to the GlobalACE Framework, developed with government agencies, industry and academia to build job-ready cyber skills."},"/trainings/mitre-attck":{title:"MITRE ATT&CK Mapped Trainings | Cybertronium",description:"Build practical, attacker-informed skills with Cybertronium's trainings mapped to the MITRE ATT&CK framework of real-world adversary tactics."},"/trainings/skillsfuture-sg":{title:"SkillsFuture Singapore Approved Cybersecurity & AI Security Training",description:"Advance your career with Cybertronium's SkillsFuture Singapore approved cybersecurity and AI security training. Gain industry-recognized skills, practical expertise, and workforce-ready certifications."},"/trainings/certified-penetration-tester":{title:"Certified Penetration Tester Training | Cybertronium",description:"Become a certified penetration tester with Cybertronium's 100% hands-on course covering real-world attack techniques across networks and apps."},"/trainings/certified-soc-analyst":{title:"Certified SOC Analyst Training | Cybertronium",description:"Cybertronium's Certified SOC Analyst course builds hands-on skills in threat detection, monitoring and incident response for SOC analyst roles."},"/trainings/certified-red-team-professional":{title:"Certified Red Team Professional (CRTP) | Cybertronium",description:"Master offensive security with Cybertronium's Certified Red Team Professional course, covering advanced adversary simulation and attack techniques."},"/trainings/certified-cyber-threat-intelligence-analyst":{title:"Certified Cyber Threat Intelligence Analyst | Cybertronium",description:"Learn to collect, analyze and act on threat data with Cybertronium's hands-on Certified Cyber Threat Intelligence Analyst training program."},"/trainings/certified-secure-developer":{title:"Certified Secure Developer Training | Cybertronium",description:"Cybertronium's Certified Secure Developer course teaches developers to identify, fix and prevent security flaws throughout the software lifecycle."},"/trainings/certified-cloud-security-professional":{title:"Certified Cloud Security Professional | AWS, Azure & GCP Security Training",description:"Master cloud security with Cybertronium's Certified Cloud Security Professional course. Learn AWS, Azure, and GCP security, cloud compliance, IAM, data protection, and incident response."},"/trainings/certified-experiential-cybersecurity-aware-user":{title:"Certified Experiential Cybersecurity Aware User | Cybertronium",description:"Experience real cyberattacks firsthand, no IT background required. Cybertronium's experiential course teaches practical ways to stay safe online."},"/trainings/certified-security-aware-user":{title:"Certified Security Aware User Training | Cybertronium",description:"Build a security-first culture with Cybertronium's Certified Security Aware User course, teaching staff to recognize and avoid everyday cyber threats."},"/trainings/certified-security-aware-cxo":{title:"Certified Security Aware CxO Training | Cybertronium",description:"Cybertronium's Certified Security Aware CxO program equips executives and leaders with the cyber risk awareness needed to guide strategic decisions."},"/contact":{title:"Contact Cybertronium | Cybersecurity Experts",description:"Get in touch with Cybertronium to discuss your cybersecurity, cloud security or training needs. Our team responds quickly to help secure your business."},"/privacy-policy":{title:"Privacy Statement | Cybertronium",description:"Read Cybertronium's privacy statement to understand how we collect, use and protect your personal data when you use our website and services."},"/terms-of-use":{title:"Terms of Use | Cybertronium",description:"Review Cybertronium's terms of use, outlining the rules and conditions for accessing and using our website and online services."},"/email-security":{title:"Email Security Challenge | Cybertronium",description:"Take the 14-day Email Security Challenge with Cybertronium and Check Point. Assess your email protection and discover hidden threats."},"/agenticaisoc":{title:"Agentic AI SOC Challenge | Cybertronium",description:"Join the Agentic AI SOC Challenge to see how Cybertronium's AI-driven approach resolves alert backlogs and accelerates threat triage."},default:{title:"Cybertronium | Cybersecurity Services, SOC & Training",description:"Cybertronium delivers penetration testing, cloud security, 24x7 SOC/MDR and ISO 17024 certified cybersecurity training for businesses across Asia."}},e="https://www.cybertronium.com",f=`${e}/android-chrome-512x512.png`;function g(a,b){let c="/"===a?"/":a.replace(/\/$/,""),g=d[c]??d.default,h=b?.title??g.title,i=b?.description??g.description,j=b?.image??f,k=b?.type??"website",l=`${e}${"/"===c?"":c}`;return{title:h,description:i,alternates:{canonical:l},openGraph:{title:h,description:i,url:l,siteName:"Cybertronium",type:k,images:[{url:j,width:512,height:512,alt:h}]},twitter:{card:"summary_large_image",title:h,description:i,images:[j]}}}}};